operation.add:
$route = '';
$path = '';
$exists = false;

foreach ($parts as $part) {
	$route .= $part . '/';

	$path .= $part;

	if (is_dir(DIR_APPLICATION . 'controller/' . $path)) {
		$path .= '/';
	} elseif (is_file(DIR_APPLICATION . 'controller/' . $path . '.php')) {
		$exists = true;
	}
}

if ($exists == true && $this->config->get('seo_license_license_key')) {
	$this->request->get['route'] = substr($route, 0, -1);
}

else {
	$this->load->model('catalog/seo');

	foreach ($data['product_description'] as $language_id => $value) {
		$name = $this->model_catalog_seo->cleanString($value['name']);

		$query = $this->db->query("SELECT * FROM " . DB_PREFIX . "url_alias WHERE keyword = '" . $this->db->escape($name) . "'");

		if ($query->num_rows) {
			$true = true;
			$count = 0;

			while ($true) {								
				$query = $this->db->query("SELECT * FROM " . DB_PREFIX . "url_alias WHERE keyword = '" . $this->db->escape($name . '-' . $count) . "'");

				if ($query->num_rows) {
					$count++;
				} else {
					$true = false;
				}
			}

			$this->db->query("INSERT INTO " . DB_PREFIX . "url_alias SET query = 'product_id=" . (int)$product_id . "', keyword = '" . $this->db->escape($name . '-' . $count) . "'");
		} else {
			$this->db->query("INSERT INTO " . DB_PREFIX . "url_alias SET query = 'product_id=" . (int)$product_id . "', keyword = '" . $this->db->escape($name) . "'");
		}

		break;
	}
}

